export default function ContactPage() {
  return (
    <main>
      <div className="page-shell">
        <section className="page-header animate-rise">
          <p className="eyebrow">Contact</p>
          <h1>Let&apos;s build something valuable</h1>
          <p>
            Open to backend-focused roles, full-stack product engineering, and contract opportunities.
          </p>
        </section>

        <div className="services-grid" style={{ marginTop: 0 }}>
          <div className="service-card animate-rise">
            <div className="service-icon">📧</div>
            <h3>Email</h3>
            <p>your.email@example.com</p>
            <a href="mailto:your.email@example.com" className="read-more">Send Email →</a>
          </div>
          <div className="service-card animate-rise" style={{ animationDelay: "80ms" }}>
            <div className="service-icon">👨‍💻</div>
            <h3>GitHub</h3>
            <p>See my public repos, commits, and project history.</p>
            <a href="https://github.com/your-handle" target="_blank" rel="noreferrer" className="read-more">View GitHub →</a>
          </div>
          <div className="service-card animate-rise" style={{ animationDelay: "160ms" }}>
            <div className="service-icon">🔗</div>
            <h3>LinkedIn</h3>
            <p>Professional profile, experience, and endorsements.</p>
            <a href="https://linkedin.com/in/your-handle" target="_blank" rel="noreferrer" className="read-more">Connect →</a>
          </div>
        </div>
      </div>
    </main>
  );
}
